68: type PanelSchemeUpgradeHandler = (panel: PanelModel) => PanelModel;
69: 
70: /**
71:  * The current version of the dashboard schema.
72:  *
73:  * NOTE: Schema version 42 is the FINAL version for the v1 dashboard API.
74:  * DO NOT increment this number or add new schema migrations.
75:  *
76:  * This is necessary due to the migration of the legacy dashboards API to the app platform.
77:  *
78:  * For panel-specific migrations, implement them as panel migrations in the
79:  * individual panel plugin migration handlers instead of adding new schema versions.
80:  *
81:  * Legacy migration instructions (for reference only):
82:  * To add a dashboard migration increment this number
83:  * and then add your migration at the bottom of 'updateSchema'
84:  * hint: search "Add migration here"
85:  *
86:  * This number also needs to be updated on the CUE schema:
87:  * kinds/dashboard/dashboard_kind.cue
88:  * Example PR: #87712
89:  */
90: export const DASHBOARD_SCHEMA_VERSION = 42;
91: export class DashboardMigrator {
92:   dashboard: DashboardModel;
93: 
94:   constructor(dashboardModel: DashboardModel) {
95:     this.dashboard = dashboardModel;
96: 
97:     // for tests to pass
98:     if (!getDataSourceSrv()) {
99:       setDataSourceSrv(new DatasourceSrv());
100:     }
101:   }
102: 
103:   updateSchema(old: any, targetSchemaVersion?: number) {
104:     let i, j, k, n;
105:     const oldVersion = this.dashboard.schemaVersion;
106:     const panelUpgrades: PanelSchemeUpgradeHandler[] = [];
107:     const finalTargetVersion = targetSchemaVersion || DASHBOARD_SCHEMA_VERSION;
108: 
109:     if (oldVersion === finalTargetVersion) {
110:       return;
111:     }
112: 
113:     // version 2 schema changes
114:     if (oldVersion < 2 && finalTargetVersion >= 2) {
115:       if (old.services) {
116:         if (old.services.filter) {
117:           this.dashboard.time = old.services.filter.time;
118:           this.dashboard.templating.list = old.services.filter.list || [];
119:         }
120:       }
121: 
122:       // we used to have graphite panel type migration logic here
123:       // but this is handled by auto migration, see public/app/features/dashboard/state/getPanelPluginToMigrateTo.ts
124:     }
125: 
126:     // schema version 3 changes
127:     if (oldVersion < 3 && finalTargetVersion >= 3) {
128:       // Panel ID assignment is now handled by ensurePanelsHaveUniqueIds() in DashboardModel
129:       // and the grid layout migration properly handles panels without IDs in rows
130:     }
131: 
132:     // schema version 4 changes
133:     if (oldVersion < 4 && finalTargetVersion >= 4) {
134:       // graph migration is handled through the auto migration
135:       // see autoMigrateAngular map in public/app/features/dashboard/state/PanelModel.ts
136:     }
137: 
138:     if (oldVersion < 6 && finalTargetVersion >= 6) {
139:       // move drop-downs to new schema
140:       const annotations = find(old.pulldowns, { type: 'annotations' });
141: 
142:       if (annotations) {
143:         this.dashboard.annotations = {
144:           list: annotations.annotations || [],
145:         };
146:       }
147: 
148:       // update template variables
149:       for (i = 0; i < this.dashboard.templating.list.length; i++) {
150:         const variable = this.dashboard.templating.list[i];
151:         if (variable.datasource === void 0) {
152:           variable.datasource = null;
153:         }
154:         if (variable.type === 'filter') {
155:           variable.type = 'query';
156:         }
157:         if (variable.type === void 0) {
158:           variable.type = 'query';
159:         }
160:         if (variable.allFormat === void 0) {
161:           delete variable.allFormat;
162:         }
163:       }
164:     }
165: 
166:     if (oldVersion < 7 && finalTargetVersion >= 7) {
167:       if (old.nav && old.nav.length) {
168:         this.dashboard.timepicker = old.nav[0];
169:       }
170:     }
171: 
172:     if (oldVersion < 8 && finalTargetVersion >= 8) {
173:       panelUpgrades.push((panel: any) => {
174:         each(panel.targets, (target) => {
175:           // update old influxdb query schema
176:           if (target.fields && target.tags && target.groupBy) {
177:             if (target.rawQuery) {
178:               delete target.fields;
179:               delete target.fill;
180:             } else {
181:               target.select = map(target.fields, (field) => {
182:                 const parts = [];
183:                 parts.push({ type: 'field', params: [field.name] });
184:                 parts.push({ type: field.func, params: [] });
185:                 if (field.mathExpr) {
186:                   parts.push({ type: 'math', params: [field.mathExpr] });
187:                 }
188:                 if (field.asExpr) {
189:                   parts.push({ type: 'alias', params: [field.asExpr] });
190:                 }
191:                 return parts;
192:               });
193:               delete target.fields;
194:               each(target.groupBy, (part) => {
195:                 if (part.type === 'time' && part.interval) {
196:                   part.params = [part.interval];
197:                   delete part.interval;
198:                 }
199:                 if (part.type === 'tag' && part.key) {
200:                   part.params = [part.key];
201:                   delete part.key;
202:                 }
203:               });
204: 
205:               if (target.fill) {
206:                 target.groupBy.push({ type: 'fill', params: [target.fill] });
207:                 delete target.fill;
208:               }
209:             }
210:           }
211:         });
212: 
213:         return panel;
214:       });
215:     }
216: 
217:     // schema version 9 changes
218:     if (oldVersion < 9 && finalTargetVersion >= 9) {
219:       // singlestat panel is automigrated to stat panel
220:       // see autoMigrateAngular map in public/app/features/dashboard/state/PanelModel.ts
221:     }
222: 
223:     // schema version 10 changes
224:     if (oldVersion < 10 && finalTargetVersion >= 10) {
225:       // move aliasYAxis changes
226:       panelUpgrades.push((panel: any) => {
227:         if (panel.type !== 'table') {
228:           return panel;
229:         }
230: 
231:         each(panel.styles, (style) => {
232:           if (style.thresholds && style.thresholds.length >= 3) {
233:             const k = style.thresholds;
234:             k.shift();
235:             style.thresholds = k;
236:           }
237:         });
238: 
239:         return panel;
240:       });
241:     }
242: 
243:     if (oldVersion < 12 && finalTargetVersion >= 12) {
244:       // update template variables
245:       each(this.dashboard.getVariables(), (templateVariable) => {
246:         if ('refresh' in templateVariable) {
247:           if (templateVariable.refresh) {
248:             templateVariable.refresh = 1;
249:           }
250:           if (!templateVariable.refresh) {
251:             templateVariable.refresh = 0;
252:           }
253:         }
254:         if ('hideVariable' in templateVariable && templateVariable.hideVariable) {
255:           templateVariable.hide = 2;
256:         } else if ('hideLabel' in templateVariable && templateVariable.hideLabel) {
257:           templateVariable.hide = 1;
258:         }
259:       });
260:     }
261: 
262:     if (oldVersion < 13 && finalTargetVersion >= 13) {
263:       // graph panel auto migrates to either barchart, bargauge, histogram or timeseries (all standard Grafana plugins)
264:       // see public/app/features/dashboard/state/getPanelPluginToMigrateTo.ts
265:     }
266: 
267:     if (oldVersion < 14 && finalTargetVersion >= 14) {
268:       this.dashboard.graphTooltip = old.sharedCrosshair ? 1 : 0;
269:     }
270: 
271:     if (oldVersion < 16 && finalTargetVersion >= 16) {
272:       this.upgradeToGridLayout(old);
273:     }
274: 
275:     if (oldVersion < 17 && finalTargetVersion >= 17) {
276:       panelUpgrades.push((panel: any) => {
277:         if (panel.minSpan) {
278:           const max = GRID_COLUMN_COUNT / panel.minSpan;
279:           const factors = getFactors(GRID_COLUMN_COUNT);
280:           // find the best match compared to factors
281:           // (ie. [1,2,3,4,6,12,24] for 24 columns)
282:           panel.maxPerRow =
283:             factors[
284:               findIndex(factors, (o) => {
285:                 return o > max;
286:               }) - 1
287:             ];
288:         }
289: 
290:         delete panel.minSpan;
291: 
292:         return panel;
293:       });
294:     }
295: 
296:     if (oldVersion < 18 && finalTargetVersion >= 18) {
297:       // migrate change to gauge options
298:       panelUpgrades.push((panel: any) => {
299:         if (panel['options-gauge']) {
300:           panel.options = panel['options-gauge'];
301:           panel.options.valueOptions = {
302:             unit: panel.options.unit,
303:             stat: panel.options.stat,
304:             decimals: panel.options.decimals,
305:             prefix: panel.options.prefix,
306:             suffix: panel.options.suffix,
307:           };
308: 
309:           // correct order
310:           if (panel.options.thresholds) {
311:             panel.options.thresholds.reverse();
312:           }
313: 
314:           // this options prop was due to a bug
315:           delete panel.options.options;
