905: function getGridHeight(height: number | string) {
906:   if (isString(height)) {
907:     height = parseInt(height.replace('px', ''), 10);
908:   }
909: 
910:   if (height < MIN_PANEL_HEIGHT) {
911:     height = MIN_PANEL_HEIGHT;
912:   }
913: 
914:   const gridHeight = Math.ceil(height / (GRID_CELL_HEIGHT + GRID_CELL_VMARGIN));
915:   return gridHeight;
916: }
