918: /**
919:  * RowArea represents dashboard row filled by panels
920:  * area is an array of numbers represented filled column's cells like
921:  *  -----------------------
922:  * |******** ****
923:  * |******** ****
924:  * |********
925:  *  -----------------------
926:  *  33333333 2222 00000 ...
927:  */
928: class RowArea {
929:   area: number[];
930:   yPos: number;
931:   height: number;
932: 
933:   constructor(height: number, width = GRID_COLUMN_COUNT, rowYPos = 0) {
934:     this.area = new Array(width).fill(0);
935:     this.yPos = rowYPos;
936:     this.height = height;
937:   }
938: 
939:   reset() {
940:     this.area.fill(0);
941:   }
942: 
943:   /**
944:    * Update area after adding the panel.
945:    */
946:   addPanel(gridPos: any) {
947:     for (let i = gridPos.x; i < gridPos.x + gridPos.w; i++) {
948:       if (!this.area[i] || gridPos.y + gridPos.h - this.yPos > this.area[i]) {
949:         this.area[i] = gridPos.y + gridPos.h - this.yPos;
950:       }
951:     }
952:     return this.area;
953:   }
954: 
955:   /**
956:    * Calculate position for the new panel in the row.
957:    */
958:   getPanelPosition(panelHeight: number, panelWidth: number, callOnce = false): any {
959:     let startPlace, endPlace;
960:     let place;
961:     for (let i = this.area.length - 1; i >= 0; i--) {
962:       if (this.height - this.area[i] > 0) {
963:         if (endPlace === undefined) {
964:           endPlace = i;
965:         } else {
966:           if (i < this.area.length - 1 && this.area[i] <= this.area[i + 1]) {
967:             startPlace = i;
968:           } else {
969:             break;
970:           }
971:         }
972:       } else {
973:         break;
974:       }
975:     }
976: 
977:     if (startPlace !== undefined && endPlace !== undefined && endPlace - startPlace >= panelWidth - 1) {
978:       const yPos = max(this.area.slice(startPlace));
979:       place = {
