50: // ConvertToFloat converts various numeric types to float64
51: func ConvertToFloat(value interface{}) (float64, bool) {
52: 	switch v := value.(type) {
53: 	case float64:
54: 		return v, true
55: 	case int:
56: 		return float64(v), true
57: 	case int64:
58: 		return float64(v), true
59: 	case float32:
60: 		return float64(v), true
61: 	case int32:
62: 		return float64(v), true
63: 	case string:
64: 		// Handle string values like "700px" - strip px suffix and parse
65: 		// This matches frontend behavior: parseInt(height.replace('px', ''), 10)
66: 		cleanStr := strings.TrimSuffix(v, "px")
67: 		if parsed, err := strconv.ParseFloat(cleanStr, 64); err == nil {
68: 			return parsed, true
69: 		}
70: 		return 0, false
71: 	default:
72: 		return 0, false
73: 	}
